'use client';

import { motion, AnimatePresence } from 'framer-motion';
import { X } from 'lucide-react';
import { useFilters } from '@/hooks/useFilters';
import { useGlobal } from '@/context/GlobalContext';
import { CATEGORIES } from '@/lib/constants';

export function FilterChips() {
    const { t } = useGlobal();
    const { filters, removeFilter, removeBooleanFilter, clearFilters, hasActiveFilters } = useFilters();

    if (!hasActiveFilters()) return null;

    const allChips = [
        ...(filters.categories || []).map((c) => ({ type: 'categories' as const, value: c, label: CATEGORIES.find(cat => cat.slug === c)?.name || c })),
        ...filters.colors.map((c) => ({ type: 'colors' as const, value: c, label: c })),
        ...filters.materials.map((m) => ({ type: 'materials' as const, value: m, label: m })),
        ...filters.brands.map((b) => ({ type: 'brands' as const, value: b, label: b })),
        ...(filters.inStock ? [{ type: 'inStock' as const, value: 'inStock', label: 'Stoktakiler' }] : []),
        ...(filters.isNew ? [{ type: 'isNew' as const, value: 'isNew', label: 'Yeni Ürünler' }] : []),
    ];

    return (
        <AnimatePresence>
            <motion.div
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: 'auto' }}
                exit={{ opacity: 0, height: 0 }}
                className="flex flex-wrap items-center gap-2 mb-8"
            >
                {allChips.map((chip) => (
                    <motion.button
                        key={`${chip.type}-${chip.value}`}
                        layout
                        initial={{ opacity: 0, scale: 0.8 }}
                        animate={{ opacity: 1, scale: 1 }}
                        exit={{ opacity: 0, scale: 0.8 }}
                        transition={{ duration: 0.2 }}
                        onClick={() => {
                            if (chip.type === 'inStock' || chip.type === 'isNew') {
                                removeBooleanFilter(chip.type);
                            } else {
                                removeFilter(chip.type, chip.value);
                            }
                        }}
                        className="group flex items-center gap-2 px-4 py-2 bg-white border border-sand-dark/30 hover:border-gold transition-all duration-300"
                    >
                        <span className="text-xs font-bold uppercase tracking-widest text-charcoal">{chip.label}</span>
                        <X size={12} className="text-charcoal/40 group-hover:text-gold transition-colors" />
                    </motion.button>
                ))}

                <button
                    onClick={clearFilters}
                    className="text-[10px] font-bold text-gold hover:text-charcoal transition-colors uppercase tracking-widest ml-2"
                >
                    {t('fav_clear_all')}
                </button>
            </motion.div>
        </AnimatePresence>
    );
}
